1	type Item = { type: string; cursed?: boolean; enchantment?: number; material?: string };
2	type QuoteStep = { op: "quote"; items: Item[] };
3	type Damage = { itemType: string; amount: number };
4	type Incident = { cause: string; damages: Damage[] };
5	type ClaimStep = { op: "claim"; policy: number; incident: Incident };
6	type Step = QuoteStep | ClaimStep;
7	type Customer = { yearsWithMHPCO: number };
8	type Scenario = { customer: Customer; steps: Step[] };
9	type QuoteResult = { premium: number };
10	type ClaimResult = { payout: number; remainingCap: number };
11	type StepResult = QuoteResult | ClaimResult;
12	
13	const PROCESSING_FEE = 5;
14	const FIRST_INSURANCE_RATE = 0.1;
15	
16	const ITEM_BASE_PREMIUMS: Record<string, number> = {
17	  sword: 100,
18	  amulet: 60,
19	  staff: 80,
20	  potion: 40,
21	  rune: 25,
22	  moonstone: 25,
23	};
24	
25	const INSURANCE_VALUE_MULTIPLIER = 10;
26	
27	const BLOCK_SIZE = 3;
28	const BLOCK_BASE_PREMIUM = 60;
29	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
30	
31	const CURSE_RATE = 0.5;
32	const HIGH_ENCHANTMENT_RATE = 0.3;
33	const HIGH_ENCHANTMENT_THRESHOLD = 5;
34	const LOYALTY_RATE = 0.2;
35	const LOYALTY_THRESHOLD_YEARS = 2;
36	const FOLLOW_UP_RATE = 0.15;
37	
38	const CAP_MULTIPLIER = 2;
39	const DEDUCTIBLE = 100;
40	const HIGH_ENCHANTMENT_REIMBURSEMENT_THRESHOLD = 8;
41	const HIGH_ENCHANTMENT_REIMBURSEMENT_RATE = 0.5;
42	
43	const sumBy = <T>(items: T[], f: (x: T) => number): number =>
44	  items.reduce((acc, x) => acc + f(x), 0);
45	
46	const baseFor = (item: Item): number => {
47	  const base = ITEM_BASE_PREMIUMS[item.type];
48	  if (base === undefined) throw new Error(`Unknown item type: ${item.type}`);
49	  return base;
50	};
51	
52	const SURCHARGE_RULES: ReadonlyArray<{ applies: (item: Item) => boolean; rate: number }> = [
53	  { applies: (item) => item.cursed === true, rate: CURSE_RATE },
54	  { applies: (item) => (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD, rate: HIGH_ENCHANTMENT_RATE },
55	];
56	
57	const surchargeFor = (item: Item): number => {
58	  const base = baseFor(item);
59	  return sumBy(SURCHARGE_RULES, (rule) => (rule.applies(item) ? base * rule.rate : 0));
60	};
61	
62	const totalSurchargeFor = (items: Item[]): number => sumBy(items, surchargeFor);
63	
64	type QuoteContext = { customer: Customer; isFollowUp: boolean };
65	
66	const DISCOUNT_RULES: ReadonlyArray<{ applies: (ctx: QuoteContext) => boolean; rate: number }> = [
67	  { applies: (ctx) => ctx.customer.yearsWithMHPCO >= LOYALTY_THRESHOLD_YEARS, rate: LOYALTY_RATE },
68	  { applies: (ctx) => ctx.isFollowUp, rate: FOLLOW_UP_RATE },
69	];
70	
71	const totalDiscountFor = (ctx: QuoteContext, totalBase: number): number =>
72	  sumBy(DISCOUNT_RULES, (rule) => (rule.applies(ctx) ? totalBase * rule.rate : 0));
73	
74	const premiumFor = (totalBase: number, totalSurcharge: number, ctx: QuoteContext): number =>
75	  Math.ceil(
76	    totalBase
77	    + totalSurcharge
78	    + totalBase * FIRST_INSURANCE_RATE
79	    - totalDiscountFor(ctx, totalBase)
80	    + PROCESSING_FEE,
81	  );
82	
83	const groupsByType = (items: Item[]): Item[][] => {
84	  const types = new Set(items.map((item) => item.type));
85	  return Array.from(types, (type) => items.filter((item) => item.type === type));
86	};
87	
88	const formsCompleteBlock = (group: Item[]): boolean =>
89	  group.length === BLOCK_SIZE && COMPONENT_TYPES.has(group[0].type);
90	
91	const baseForGroup = (group: Item[]): number =>
92	  formsCompleteBlock(group) ? BLOCK_BASE_PREMIUM : sumBy(group, baseFor);
93	
94	const totalBaseFor = (items: Item[]): number =>
95	  sumBy(groupsByType(items), baseForGroup);
96	
97	const insuranceValueFor = (item: Item): number =>
98	  baseFor(item) * INSURANCE_VALUE_MULTIPLIER;
99	
100	const insuranceSumFor = (items: Item[]): number => sumBy(items, insuranceValueFor);
101	
102	type Policy = { items: Item[]; remainingCap: number };
103	
104	const newPolicy = (items: Item[]): Policy => ({
105	  items,
106	  remainingCap: insuranceSumFor(items) * CAP_MULTIPLIER,
107	});
108	
109	const reimbursementRateFor = (item: Item): number =>
110	  (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_REIMBURSEMENT_THRESHOLD
111	    ? HIGH_ENCHANTMENT_REIMBURSEMENT_RATE
112	    : 1;
113	
114	const payoutForDamage = (damage: Damage, items: Item[]): number => {
115	  const item = items.find((i) => i.type === damage.itemType)!;
116	  const reimbursed = damage.amount * reimbursementRateFor(item);
117	  return Math.max(0, reimbursed - DEDUCTIBLE);
118	};
119	
120	type DamageValidation = {
121	  invalid: (damage: Damage, items: Item[]) => boolean;
122	  message: (damage: Damage) => string;
123	};
124	
125	const DAMAGE_VALIDATIONS: ReadonlyArray<DamageValidation> = [
126	  {
127	    invalid: (d) => d.amount < 0,
128	    message: (d) => `Damage amount must be non-negative: ${d.amount}`,
129	  },
130	  {
131	    invalid: (d, items) => !items.some((i) => i.type === d.itemType),
132	    message: (d) => `Claim references item type not in policy: ${d.itemType}`,
133	  },
134	];
135	
136	const countByKey = <T>(items: T[], key: (item: T) => string): Map<string, number> => {
137	  const counts = new Map<string, number>();
138	  for (const item of items) {
139	    const k = key(item);
140	    counts.set(k, (counts.get(k) ?? 0) + 1);
141	  }
142	  return counts;
143	};
144	
145	const findOverclaimedType = (damages: Damage[], items: Item[]): string | undefined => {
146	  const damageCounts = countByKey(damages, (d) => d.itemType);
147	  const itemCounts = countByKey(items, (i) => i.type);
148	  for (const [type, dc] of damageCounts) {
149	    if (dc > (itemCounts.get(type) ?? 0)) return type;
150	  }
151	  return undefined;
152	};
153	
154	const validateDamageCountsAgainstPolicy = (damages: Damage[], items: Item[]): void => {
155	  const type = findOverclaimedType(damages, items);
156	  if (type) throw new Error(`More damages of type ${type} than insured items`);
157	};
158	
159	const validateDamagesAgainstPolicy = (damages: Damage[], items: Item[]): void => {
160	  for (const rule of DAMAGE_VALIDATIONS) {
161	    const bad = damages.find((d) => rule.invalid(d, items));
162	    if (bad) throw new Error(rule.message(bad));
163	  }
164	  validateDamageCountsAgainstPolicy(damages, items);
165	};
166	
167	const processClaim = (policy: Policy, incident: Incident): ClaimResult => {
168	  validateDamagesAgainstPolicy(incident.damages, policy.items);
169	  const grossPayout = sumBy(incident.damages, (d) => payoutForDamage(d, policy.items));
170	  const payout = Math.floor(Math.min(grossPayout, policy.remainingCap));
171	  policy.remainingCap -= payout;
172	  return { payout, remainingCap: policy.remainingCap };
173	};
174	
175	const quoteFor = ({ items }: QuoteStep, ctx: QuoteContext): QuoteResult => ({
176	  premium: premiumFor(totalBaseFor(items), totalSurchargeFor(items), ctx),
177	});
178	
179	type ScenarioState = { customer: Customer; policies: Policy[]; quoteCount: number };
180	
181	const handleQuote = (step: QuoteStep, state: ScenarioState): QuoteResult => {
182	  const ctx: QuoteContext = { customer: state.customer, isFollowUp: state.quoteCount > 0 };
183	  state.quoteCount += 1;
184	  state.policies.push(newPolicy(step.items));
185	  return quoteFor(step, ctx);
186	};
187	
188	const handleStep = (step: Step, state: ScenarioState): StepResult =>
189	  step.op === "quote"
190	    ? handleQuote(step, state)
191	    : processClaim(state.policies[step.policy], step.incident);
192	
193	export const processScenario = (input: Scenario): { results: StepResult[] } => {
194	  const state: ScenarioState = { customer: input.customer, policies: [], quoteCount: 0 };
195	  const results = input.steps.map((step) => handleStep(step, state));
196	  return { results };
197	};
